"""Tikhonov Gauss-Newton inverse method code for SSA inversions."""

import PISM
from PISM.invert.ssa import InvSSASolver

class InvSSASolver_TikhonovGN(InvSSASolver):
    """Tikhonov Gauss-Newton inverse solver for SSA basal yield stress.

    Solves an inverse problem for basal yield stress (tauc) using a
    Tikhonov-regularized Gauss-Newton method. The solver minimizes a
    combined objective functional consisting of a state misfit term
    (difference between modeled and observed velocities) and a design
    regularization term (penalty on the design variable).

    Parameters
    ----------
    sbrun : PISM.ssa.SSARun
        SSA run object containing the SSA model, grid, and model data.
    method : str
        Inversion method identifier passed to the parent class.

    Attributes
    ----------
    solver : PISM.IP_SSATaucTikhonovGNSolver or None
        The underlying Tikhonov Gauss-Newton solver instance. Set to
        ``None`` until :meth:`solveInverse` is called.
    target_misfit : float
        Target root misfit for the inversion, read from the command-line
        option ``-inv_target_misfit`` (in m/year, then scaled).
    listeners : list
        List of iteration listener objects.

    Raises
    ------
    RuntimeError
        If the required command-line option ``-inv_target_misfit`` is not set.

    See Also
    --------
    PISM.invert.ssa.InvSSASolver : Parent class providing the base interface.
    """

    def __init__(self, sbrun, method):
        """Initialize the Tikhonov Gauss-Newton inverse SSA solver.

        Parameters
        ----------
        sbrun : PISM.ssa.SSARun
            SSA run object containing the SSA model, grid, and model data.
        method : str
            Inversion method identifier passed to the parent class.

        Raises
        ------
        RuntimeError
            If the required command-line option ``-inv_target_misfit`` is
            not set.
        """
        self.solver = None
        InvSSASolver.__init__(self, sbrun, method)

        target_misfit = PISM.OptionReal("-inv_target_misfit",
                                        "m/year; desired root misfit for inversions", 0.0)

        if target_misfit.is_set():
            self.target_misfit = target_misfit.value()
        else:
            raise RuntimeError("Missing required option -inv_target_misfit")

        # FIXME: m_vel_scale is not defined (what are the units?)
        self.target_misfit = self.target_misfit / m_vel_scale

        self.listeners = []

    def solveForward(self, zeta, out=None):
        """Solve the forward SSA problem for a given design variable.

        Linearizes the SSA at the given design variable ``zeta`` and
        returns the resulting velocity solution.

        Parameters
        ----------
        zeta : PISM.Scalar
            Design variable (parameterization of basal yield stress).
        out : PISM.Vector or None, optional
            If provided, the velocity solution is copied into this vector.
            If ``None``, the solver's internal solution reference is returned
            directly.

        Returns
        -------
        PISM.Vector
            The SSA velocity solution.

        Raises
        ------
        PISM.AlgorithmFailureException
            If the SSA linearization fails.
        """
        ssa = self.sbrun.solver

        reason = ssa.linearize_at(zeta)
        if reason.failed():
            raise PISM.AlgorithmFailureException(reason.description())
        if out is not None:
            out.copy_from(ssa.solution())
        else:
            out = ssa.solution()
        return out

    def solveInverse(self, zeta0, u_obs, zeta_inv):
        """Run the Tikhonov Gauss-Newton inverse solve.

        Sets up and executes the Gauss-Newton solver to find a design
        variable (basal yield stress parameterization) that produces
        modeled velocities matching the observations within the target
        misfit.

        If the command-line flag ``-inv_test_adjoint`` is set, an adjoint
        symmetry test is performed instead of the full solve, and the
        program exits.

        Parameters
        ----------
        zeta0 : PISM.Scalar
            Background (prior) value of the design variable used in the
            regularization term.
        u_obs : PISM.Vector
            Observed surface velocities to fit.
        zeta_inv : PISM.Scalar
            Initial guess for the design variable; updated in place with
            the solution.

        Returns
        -------
        PISM.TerminationReason
            Reason the solver terminated (e.g., converged, iteration
            limit reached).
        """
        eta = self.config.get_number("inverse.tikhonov.penalty_weight")

        (designFunctional, stateFunctional) = PISM.invert.ssa.createTikhonovFunctionals(self.sbrun)
        self.solver = PISM.IP_SSATaucTikhonovGNSolver(self.sbrun.solver, zeta0, u_obs, eta, designFunctional, stateFunctional)

        vel_scale = self.sbrun.grid.ctx().config().get_number("inverse.ssa.velocity_scale")
        self.solver.setTargetMisfit(self.target_misfit / vel_scale)

#    pl = [ TikhonovIterationListenerAdaptor(self,l) for l in self.listeners ]
        pl = []
        for l in pl:
            self.solver.addListener(l)
        self.solver.setInitialGuess(zeta_inv)

        if PISM.OptionBool("-inv_test_adjoint", ""):
            self.solver.init()
            grid = self.sbrun.grid
            d1 = PISM.vec.randVectorS(grid, 1)
            d2 = PISM.vec.randVectorS(grid, 1)
            y1 = PISM.Scalar(grid, '')
            y2 = PISM.Scalar(grid, '')
            self.solver.apply_GN(d1, y1)
            self.solver.apply_GN(d2, y2)
            ip1 = y1.get_vec().dot(d2.get_vec())
            ip2 = y2.get_vec().dot(d1.get_vec())
            PISM.logging.logMessage("ip1 %.10g ip2 %.10g\n" % (ip1, ip2))
            PISM.logging.logMessage("ip1 %g ip2 %g\n" % (ip1, ip2))
            exit(0)

        vecs = self.sbrun.modeldata.vecs
        if vecs.has('zeta_fixed_mask'):
            self.sbrun.solver.set_tauc_fixed_locations(vecs.zeta_fixed_mask)

        return self.solver.solve()

    def inverseSolution(self):
        """Retrieve the design and state solutions from the last inverse solve.

        Returns
        -------
        zeta : PISM.Scalar
            The optimal design variable (basal yield stress
            parameterization) found by the solver.
        u : PISM.Vector
            The modeled velocity field corresponding to the optimal
            design variable.
        """
        zeta = self.solver.designSolution()
        u = self.solver.stateSolution()
        return (zeta, u)
